use std::cmp::Ordering;

// State structure for the priority queue. We prioritize smaller time, then larger color.
#[derive(Copy, Clone, Eq, PartialEq)]
struct State {
    time: i64,
    color: i64,
    r: i64,
    c: i64,
}

// Implement Ord for State to ensure that the "best" state (min time, max color) has the highest priority
// in Rust's Max Heap (BinaryHeap).
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Priority 1: Time (Minimize T -> Maximize -T). Reverse comparison of time.
        match other.time.cmp(&self.time) {
            Ordering::Equal => {
                // Priority 2: Color (Maximize C). Normal comparison of color.
                self.color.cmp(&other.color)
            }
            other_cmp => other_cmp,
        }
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}


// Helper structure to store the best known state for a cell
