struct CellState {
    time: i64, // Minimum time to reach
    color: i64, // Color associated with that minimum time (or max color if ties)
}

// Constant representing infinity time
const INF_TIME: i64 = 2_000_000_000; // Sufficiently large value since N*M <= 10^5

fn solve(n: i64, m: i64, sources: Vec<Vec<i64>>) -> Vec<Vec<i64>> {
    let rows = n as usize;
    let cols = m as usize;

    // State tracking grid
    let mut cell_states = vec![vec![CellState { time: INF_TIME, color: 0 }; cols]; rows];

    let mut pq = BinaryHeap::new();

    // 1. Initialization
    for source in sources {
        let r = source[0] as usize;
        let c = source[1] as usize;
        let color = source[2];

        // Initialize source points
        if cell_states[r][c].time == INF_TIME {
            cell_states[r][c] = CellState { time: 0, color: color };
            pq.push(State { time: 0, color: color, r: r as i64, c: c as i64 });
        } else if color > cell_states[r][c].color {
            // If a cell is a source for multiple colors (though coordinates are unique, this handles potential logic overlap)
             cell_states[r][c] = CellState { time: 0, color: color };
             pq.push(State { time: 0, color: color, r: r as i64, c: c as i64 });
        }
    }

    let directions = [(0, 1), (0, -1), (1, 0), (-1, 0)];

    // 2. Dijkstra's Process
    while let Some(State { time: t, color: c, r: cr, c: cc }) = pq.pop() {
        let r_idx = cr as usize;
        let c_idx = cc as usize;

        let current_best = cell_states[r_idx][c_idx];

        // Stale check: If the state popped is worse than the recorded best state, ignore it.
        // Note: We check against current_best because PQ might hold multiple entries for the same cell.
        if t > current_best.time || (t == current_best.time && c < current_best.color) {
             continue;
        }

        // Explore neighbors
        for &(dr, dc) in directions.iter() {
            let nr = cr + dr;
            let nc = cc + dc;

            // Boundary check
            if nr >= 0 && nr < n && nc >= 0 && nc < m {
                let nr_usize = nr as usize;
                let nc_usize = nc as usize;

                let new_time = t + 1;
                let new_color = c;

                let old_state = cell_states[nr_usize][nc_usize];

                // Relaxation Condition Check: Is (new_time, new_color) strictly better than (old_state.time, old_state.color)?
                let is_better = if new_time < old_state.time {
                    // Case 1: Strictly faster arrival
                    true
                } else if new_time == old_state.time {
                    // Case 2: Simultaneous arrival, higher color wins
                    new_color > old_state.color
                } else {
                    // Case 3: Slower arrival
                    false
                };

                if is_better {
                    // Update state
                    cell_states[nr_usize][nc_usize] = CellState { time: new_time, color: new_color };

                    // Push to PQ
                    pq.push(State { 
                        time: new_time, 
                        color: new_color, 
                        r: nr, 
                        c: nc 
                    });
                }
            }
        }
    }

    // 3. Construct the final result grid
    let mut result_grid = vec![vec![0; cols]; rows];
    for r in 0..rows {
        for c in 0..cols {
            // If cell_states[r][c].time is INF_TIME, the color remains 0 (uncolored), which is correct.
            result_grid[r][c] = cell_states[r][c].color;
        }
    }

    result_grid
