    color: i64,
    r: i64,
    c: i64,
}

// Implement custom comparison for Min-Time, Max-Color behavior in Rust's Max-Heap (BinaryHeap).
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // 1. Prioritize smaller time (Min-Heap behavior for time)
        // Since BinaryHeap is a Max-Heap, we reverse the order for time.
        if self.time != other.time {
            return other.time.cmp(&self.time); // Reverse comparison on time
        }
        // 2. If times are equal, prioritize larger color (Max-Heap behavior for color)
        return self.color.cmp(&other.color);
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn solve(n: i64, m: i64, sources: Vec<Vec<i64>>) -> Vec<Vec<i64>> {
    // Grid to store the final determined state: (min_time, final_color)
    // Initialize time to infinity and color to 0 (uncolored/unreached state).
    const INF: i64 = std::i64::MAX;
    let mut dist = vec![vec![(INF, 0); m as usize]; n as usize];

    // Priority Queue: Min-Time, Max-Color
    let mut pq = BinaryHeap::new();

    // 1. Seeding the sources
    for source in sources {
        let r = source[0];
        let c = source[1];
        let color = source[2];

        let r_usize = r as usize;
        let c_usize = c as usize;

        // Check if this source provides an improvement over the initial state (T=0)
        if 0 < dist[r_usize][c_usize].0 || (0 == dist[r_usize][c_usize].0 && color > dist[r_usize][c_usize].1) {
             // Since sources are guaranteed to be distinct and uncolored initially, this only sets up T=0, C=color
            dist[r_usize][c_usize] = (0, color);
            pq.push(State { time: 0, color: color, r: r, c: c });
        }
    }

    let dr = [0, 0, 1, -1];
    let dc = [1, -1, 0, 0];

    // 2. Dijkstra/BFS loop
    while let Some(State { time: t_curr, color: c_curr, r: r_curr, c: c_curr }) = pq.pop() {
        let r_curr_usize = r_curr as usize;
        let c_curr_usize = c_curr as usize;

        // Check for stale entry
        let (t_existing, c_existing) = dist[r_curr_usize][c_curr_usize];
        if t_curr > t_existing || (t_curr == t_existing && c_curr < c_existing) {
            continue;
        }

        // Explore neighbors
        for i in 0..4 {
            let r_next = r_curr + dr[i];
            let c_next = c_curr + dc[i];

            // Boundary checks
            if r_next < 0 || r_next >= n || c_next < 0 || c_next >= m {
                continue;
            }

            let r_next_usize = r_next as usize;
            let c_next_usize = c_next as usize;

            let t_next = t_curr + 1;
            let c_next = c_curr; // Color spreads

            let (t_existing_next, c_existing_next) = dist[r_next_usize][c_next_usize];

            let should_update = 
                t_next < t_existing_next || 
                (t_next == t_existing_next && c_next > c_existing_next);

            if should_update {
                dist[r_next_usize][c_next_usize] = (t_next, c_next);
                pq.push(State { time: t_next, color: c_next, r: r_next, c: c_next });
            }
        }
    }

    // 3. Construct the final result grid
    let mut result = vec![vec![0; m as usize]; n as usize];
    for r in 0..n as usize {
        for c in 0..m as usize {
            // The final color is stored in the second element of the pair
            result[r][c] = dist[r][c].1;
        }
    }

    result
}
